DROP SEQUENCE IF EXISTS `sequence_tenant`;
CREATE SEQUENCE `sequence_tenant` start with 1 minvalue 0 maxvalue 9223372036854775806 increment by 1 nocache nocycle ENGINE=InnoDB;
DO SETVAL(`sequence_tenant`, 28, 0);

DROP TABLE IF EXISTS `DATABASECHANGELOG`;
CREATE TABLE `DATABASECHANGELOG` (
 `ID` varchar(255) NOT NULL,
 `AUTHOR` varchar(255) NOT NULL,
 `FILENAME` varchar(255) NOT NULL,
 `DATEEXECUTED` datetime NOT NULL,
 `ORDEREXECUTED` int(11) NOT NULL,
 `EXECTYPE` varchar(10) NOT NULL,
 `MD5SUM` varchar(35) DEFAULT NULL,
 `DESCRIPTION` varchar(255) DEFAULT NULL,
 `COMMENTS` varchar(255) DEFAULT NULL,
 `TAG` varchar(255) DEFAULT NULL,
 `LIQUIBASE` varchar(20) DEFAULT NULL,
 `CONTEXTS` varchar(255) DEFAULT NULL,
 `LABELS` varchar(255) DEFAULT NULL,
 `DEPLOYMENT_ID` varchar(10) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `DATABASECHANGELOGLOCK`;
CREATE TABLE `DATABASECHANGELOGLOCK` (
 `ID` int(11) NOT NULL,
 `LOCKED` bit(1) NOT NULL,
 `LOCKGRANTED` datetime DEFAULT NULL,
 `LOCKEDBY` varchar(255) DEFAULT NULL,
 PRIMARY KEY (`ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `tenant_dpa_signature`;
DROP TABLE IF EXISTS `tenant_dpa_version`;
DROP TABLE IF EXISTS `tenant`;
CREATE TABLE `tenant` (
 `id` bigint(21) NOT NULL,
 `name` varchar(40) NOT NULL,
 `subdomain` varchar(255) NOT NULL,
 `licensing_allowed_users` int(11) DEFAULT NULL,
 `theming_logo` longtext DEFAULT NULL,
 `theming_favicon` longtext DEFAULT NULL,
 `theming_primary_color` varchar(15) DEFAULT NULL,
 `theming_secondary_color` varchar(15) DEFAULT NULL,
 `content_impressum` longtext DEFAULT NULL,
 `content_claim` varchar(1024) DEFAULT NULL,
 `settings` varchar(4000) DEFAULT NULL,
 `content_privacy` longtext DEFAULT NULL,
 `content_termsandconditions` longtext DEFAULT NULL,
 `create_date` datetime NOT NULL DEFAULT utc_timestamp(),
 `update_date` datetime NOT NULL DEFAULT utc_timestamp(),
 `privacy_activation_date` datetime DEFAULT NULL,
 `termsandconditions_activation_date` datetime DEFAULT NULL,
 `theming_association_logo` longtext DEFAULT NULL,
 `address` varchar(255) DEFAULT NULL,
 `description` text DEFAULT NULL,
 `content_dpa` longtext DEFAULT NULL,
 `dpa_activation_date` datetime DEFAULT NULL,
 PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;

DROP SEQUENCE IF EXISTS `sequence_tenant_admin_controls`;
CREATE SEQUENCE sequence_tenant_admin_controls
    INCREMENT BY 1
    MINVALUE = 1
NOMAXVALUE
START WITH 1
CACHE 0;

DROP TABLE IF EXISTS `tenant_admin_controls`;
CREATE TABLE tenant_admin_controls (
                                       id BIGINT NOT NULL,
                                       controls LONGTEXT NOT NULL,
                                       update_date DATETIME NOT NULL DEFAULT (UTC_TIMESTAMP),
                                       PRIMARY KEY (id)
);

-- AVV/Legal (TenantService changesets 0016-0019): DPA signature + version history
DROP SEQUENCE IF EXISTS `SEQUENCE_TENANT_DPA_SIGNATURE`;
CREATE SEQUENCE `SEQUENCE_TENANT_DPA_SIGNATURE` start with 100000 increment by 1;
DO SETVAL(`SEQUENCE_TENANT_DPA_SIGNATURE`, 100000, 0);

CREATE TABLE `tenant_dpa_signature` (
 `id` bigint(21) NOT NULL,
 `tenant_id` bigint(21) NOT NULL,
 `dpa_version` datetime DEFAULT NULL,
 `signer_name` varchar(255) DEFAULT NULL,
 `signer_position` varchar(255) DEFAULT NULL,
 `signer_is_member` tinyint(1) DEFAULT NULL,
 `lang` varchar(10) DEFAULT NULL,
 `signature_status` varchar(20) NOT NULL DEFAULT 'PENDING',
 `signed_at` datetime DEFAULT NULL,
 `create_date` datetime NOT NULL,
 `token_hash` varchar(64) DEFAULT NULL,
 `token_expires_at` datetime DEFAULT NULL,
 `signer_email` varchar(255) DEFAULT NULL,
 `signer_organisation` varchar(255) DEFAULT NULL,
 `forwarded_by_user_id` varchar(64) DEFAULT NULL,
 `source` varchar(64) DEFAULT NULL,
 PRIMARY KEY (`id`),
 KEY `idx_tenant_dpa_signature_tenant` (`tenant_id`),
 CONSTRAINT `fk_tenant_dpa_signature_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenant` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP SEQUENCE IF EXISTS `SEQUENCE_TENANT_DPA_VERSION`;
CREATE SEQUENCE `SEQUENCE_TENANT_DPA_VERSION` start with 100000 increment by 1;
DO SETVAL(`SEQUENCE_TENANT_DPA_VERSION`, 100000, 0);

CREATE TABLE `tenant_dpa_version` (
 `id` bigint(21) NOT NULL,
 `tenant_id` bigint(21) NOT NULL,
 `content` longtext DEFAULT NULL,
 `activation_date` datetime NOT NULL,
 `create_date` datetime NOT NULL,
 PRIMARY KEY (`id`),
 KEY `idx_tenant_dpa_version_tenant` (`tenant_id`),
 CONSTRAINT `fk_tenant_dpa_version_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenant` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


